+        <span>@_errorMessage</span>
+        <button class="btn btn-outline-danger btn-sm" @onclick="RetryAsync">Retry</button>
+    </div>
+}
+
+@if (_recipes is null && _errorMessage is null)
+{
+    <p><em>Loading recipes...</em></p>
+}
+else if (_recipes is not null)
+{
+    @if (_isRefreshing)
+    {
+        <div class="text-muted mb-2"><small>Refreshing…</small></div>
+    }
+
+    @if (_recipes.Count == 0)
+    {
+        <p>No recipes found for this cuisine.</p>
+    }
+    else
+    {
+        <table class="table">
+            <thead>
+                <tr>
+                    <th>Title</th>
+                    <th>Description</th>
+                    <th>Prep Time (min)</th>
+                </tr>
+            </thead>
+            <tbody>
+                @foreach (var recipe in GetSortedRecipes())
+                {
+                    <tr>
+                        <td>@recipe.Title</td>
+                        <td>@recipe.Description</td>
+                        <td>@recipe.PrepTimeMinutes</td>
+                    </tr>
+                }
+            </tbody>
+        </table>
+    }
+}
+
+@code {
+    [Parameter]
+    public int CuisineId { get; set; }
+
+    [SupplyParameterFromQuery(Name = "sort")]
+    public string? Sort { get; set; }
+
+    private List<Recipe>? _recipes;
+    private bool _isRefreshing;
+    private string? _errorMessage;
+
+    private int _loadedCuisineId;
+    private CancellationTokenSource? _cts;
+
+    protected override async Task OnParametersSetAsync()
+    {
+        // Only reload when the cuisine changes, not when sort changes.
+        if (CuisineId == _loadedCuisineId && _recipes is not null)
+        {
+            return;
+        }
+
+        await LoadRecipesAsync();
+    }
+
+    private async Task LoadRecipesAsync()
+    {
+        // Cancel any in-flight request for the previous cuisine.
+        CancelPendingLoad();
+
+        _errorMessage = null;
+        _isRefreshing = _recipes is not null;
+        _loadedCuisineId = CuisineId;
+
+        var cts = new CancellationTokenSource();
+        _cts = cts;
+
+        try
+        {
+            var result = await RecipeService.GetByCuisineAsync(CuisineId, cts.Token);
+
+            // Guard against a stale callback after cancellation.
+            if (cts.Token.IsCancellationRequested)
+            {
+                return;
+            }
+
+            _recipes = result;
+            _errorMessage = null;
+        }
+        catch (OperationCanceledException)
+        {
+            // Expected when the user navigated to a different cuisine or left the page.
+        }
+        catch (TimeoutException ex)
+        {
+            Logger.LogError(ex, "Timeout fetching recipes for cuisine {CuisineId}", CuisineId);
+            _errorMessage = "The request timed out. Please try again.";
+        }
+        catch (Exception ex)
+        {
+            Logger.LogError(ex, "Error fetching recipes for cuisine {CuisineId}", CuisineId);
+            _errorMessage = "Something went wrong while loading recipes. Please try again.";
+        }
+        finally
+        {
+            _isRefreshing = false;
+        }
+    }
+
+    private IEnumerable<Recipe> GetSortedRecipes()
+    {
+        if (_recipes is null)
+        {
+            return [];
+        }
+
+        return string.Equals(Sort, "popular", StringComparison.OrdinalIgnoreCase)
+            ? _recipes.OrderBy(r => r.PrepTimeMinutes)
+            : _recipes.OrderByDescending(r => r.Id);
+    }
+
+    private async Task RetryAsync()
+    {
+        _errorMessage = null;
+        _loadedCuisineId = 0; // Reset so LoadRecipesAsync proceeds.
+        await LoadRecipesAsync();
+    }
+
+    private void CancelPendingLoad()
+    {
+        _cts?.Cancel();
+        _cts?.Dispose();
+        _cts = null;
+    }
+
+    public void Dispose()
+    {
+        CancelPendingLoad();
+    }
+}
